parameters.jsCode:
const rows = $input.all().map(i => i.json);
const today = new Date();
const filtered = rows.filter(r => {
  const appliedDate = new Date(r['Applied Date']);
  const daysSince = (today - appliedDate) / (1000*60*60*24);
  return daysSince >= 5 && r['Follow-up Sent'] !== 'Yes';
});
return filtered.map(r => ({ json: r }));

const email = $input.first().json;
const subject = email.subject || '';
const from = email.from || '';

// Try to extract company from subject or sender domain
let company = '';
const domainMatch = from.match(/@([^.]+)/);
if (domainMatch) {
  company = domainMatch[1];
}

return [{ json: { company, emailSubject: subject, emailFrom: from, emailBody: email.snippet || email.textPlain || '' } }];

