parameters.jsCode:
const rows = $input.all().map(i => i.json);

const applied = rows.filter(r => r.Status === 'Applied').length;
const portal = rows.filter(r => r.Status === 'Portal Applied').length;
const followup = rows.filter(r => r.Status === 'Follow-up Sent').length;
const replied = rows.filter(r => r.Status === 'Replied').length;
const interview = rows.filter(r => r.Status === 'Interview').length;
const rejected = rows.filter(r => r.Status === 'Rejected').length;
const skipped = rows.filter(r => r.Status === 'Skipped').length;
const total = applied + portal;
const rate = total > 0 ? Math.round((replied/total)*100) : 0;

return [{ json: { 
  applied, 
  portal, 
  followup, 
  replied, 
  interview, 
  rejected, 
  skipped, 
  rate 
} }];

